extra_harness_helpers:
class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def _to_linked_list(values):
    dummy = ListNode()
    cur = dummy
    for v in values:
        cur.next = ListNode(v)
        cur = cur.next
    return dummy.next

def _to_list(node):
    out = []
    while node:
        out.append(node.val)
        node = node.next
    return out

def _wrapped_add_two_numbers(l1, l2):
    return _to_list(addTwoNumbers(_to_linked_list(l1), _to_linked_list(l2)))
